// ─── Types ────────────────────────────────────────────────────────────────────

export type GeoCode = 'UK' | 'US' | 'JP' | 'DE' | 'ST'
export type DemoStatus = 'Reviewed' | 'Canceled' | 'Needs Review' | 'DELETED' | 'NEEDS REVIEW'
export type DemoType =
  | 'VIP'
  | 'Media'
  | 'External'
  | 'OEM Support'
  | 'Performance Check'
  | 'Friend & Family'
  | 'Conference'
  | 'Candidate'

export interface DemoRequest {
  id: string
  db_id?: number | null
  status: DemoStatus
  geo: GeoCode
  type: string
  requester: string
  approver: string
  organization: string
  host: string
  date_requested: string   // YYYY-MM-DD
  demo_date: string        // YYYY-MM-DD
  start_time: string       // HH:MM
  end_time: string         // HH:MM
  vehicle_type: string
  total_guests: number
  total_vehicles: number
  lead_days: number
  readiness_date: string | null
  slack_link: string | null
  cancel_reason: string | null
  channel: string
  description: string
}

export interface Interventions {
  comfort_stop?: number
  disengagement?: number
  takeover?: number
  collision_avoidance?: number
  blue_light?: number
  power_cycle?: number
  ui_crash?: number
  gps_loss?: number
}

export interface PostDemoSession {
  id: string
  model: string
  aux_model: string
  vehicle_id: string
  geo: GeoCode
  demo_type: DemoType
  operator: string
  route: string
  weather: string
  feature_rating: number   // 1-5
  smoothness_rating: number
  active_issues_list: string[]
  uds_count: number
  total_interventions: number
  interventions: Interventions
  model_behavior: string
  driving_feature: string
  comments: string
  demo_datetime: string    // YYYY-MM-DDTHH:MM
}

export interface OperationFeedback {
  id: string
  date: string             // YYYY-MM-DD
  geo: GeoCode
  operator: string
  satisfaction_score: number // 1-5
  reported_issues: string[]
  comments: string
  feedback_host: string
}

