// ─── Helper Functions ─────────────────────────────────────────────────────────

/** Normalize geo code to uppercase canonical form */
export function normGeo(raw: string): GeoCode {
  const upper = raw.toUpperCase().trim()
  if (['UK','US','JP','DE'].includes(upper)) return upper as GeoCode
  return 'UK'
}

/** Normalize status strings */
export function normStatus(raw: string): DemoStatus {
  const trimmed = raw.trim()
  if (trimmed === 'Reviewed') return 'Reviewed'
  if (trimmed === 'Canceled') return 'Canceled'
  if (trimmed === 'Needs Review' || trimmed === 'NEEDS REVIEW') return 'Needs Review'
  if (trimmed === 'DELETED') return 'DELETED'
  return 'Needs Review'
}

export interface LeadBand {
  key: 'critical' | 'short' | 'good' | 'excellent' | 'unknown'
  label: string
  color: string
}

/** Classify lead time into bands */
export function leadBand(days: number | null | undefined): LeadBand {
  if (days == null || days === 0) return { key:'unknown',   label:'UNKNOWN',   color:'#94A3B8' }
  if (days <= 2)                  return { key:'critical',  label:'CRITICAL',  color:'#F20F31' }
  if (days <= 4)                  return { key:'short',     label:'SHORT',     color:'#F59E0B' }
  if (days <= 7)                  return { key:'good',      label:'GOOD',      color:'#0052FF' }
  return                                 { key:'excellent', label:'EXCELLENT', color:'#10B981' }
}

/** Calculate overall readiness rate (% of non-canceled demos with readiness_date set) */
export function calcReadinessRate(): number {
  const eligible = demoRequests.filter(d => d.status !== 'Canceled' && d.status !== 'DELETED')
  if (eligible.length === 0) return 0
  const ready = eligible.filter(d => d.readiness_date !== null)
  return Math.round((ready.length / eligible.length) * 100)
}

/** Return demos that are flagged as delayed (lead_days 0-2, not Canceled/DELETED) */
export function getDelayedOrders(): DemoRequest[] {
  return demoRequests.filter(d => {
    const notDone = d.status !== 'Canceled' && d.status !== 'DELETED'
    return notDone && d.lead_days < 3
  })
}
